using QBEngineer.Core.Entities;
using QBEngineer.Core.Enums;
using QBEngineer.Data.Context;

using Serilog;

namespace QBEngineer.Api.Data.TrainingContent;

public class SalesOrdersTraining : TrainingContentBase
{
    public SalesOrdersTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Sales Orders Overview",
            Slug = "sales-orders-overview",
            Summary = "What sales orders are, their lifecycle from draft to completion, line items, and how they connect to quotes, jobs, shipments, and invoices.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/sales-orders"]""",
            Tags = """["sales-orders","sales","order-management"]""",
            ContentJson = """{"body":"## Sales Orders Overview\n\nA Sales Order (SO) is a confirmed commitment to deliver specific parts to a customer at agreed-upon prices. It is the central document in the order-to-cash workflow, linking upstream quotes to downstream production, shipping, and invoicing.\n\n### What Is a Sales Order?\n\nA sales order captures:\n- **Who** is ordering (customer, with optional customer PO reference)\n- **What** they want (line items — each referencing a part, quantity, and unit price)\n- **When** they need it (requested delivery date)\n- **Payment terms** (credit terms like Net 30, Net 60, etc.)\n- **Tax** (tax rate applied to the subtotal)\n\nEach SO is assigned a unique order number automatically. The order number appears throughout the system — on shipments, invoices, and the kanban board — so you can always trace back to the original commitment.\n\n### Sales Order Lifecycle\n\nSales orders move through a defined status progression:\n\n1. **Draft** — The order is being prepared. You can still edit all fields, add/remove line items, and delete the order entirely. Draft orders have not been committed to the customer.\n\n2. **Confirmed** — The order has been reviewed and confirmed. This locks in the commitment. The confirmed date is recorded automatically. From here, production can begin.\n\n3. **In Production** — Jobs have been created from the SO lines and work is underway on the shop floor. The SO moves to this status when linked jobs are active.\n\n4. **Partially Shipped** — Some line items have been shipped but others remain. Each line tracks its own shipped quantity vs. ordered quantity, so you can see exactly what's outstanding.\n\n5. **Shipped** — All line items have been fully shipped. The order is complete from a fulfillment perspective.\n\n6. **Completed** — The order is fully closed — shipped and invoiced. No further action needed.\n\n7. **Cancelled** — The order was cancelled before completion. Cancellation is allowed from Draft or Confirmed status only. Once production has started, you cannot cancel.\n\n### Line Items\n\nEach sales order contains one or more line items. A line item includes:\n- **Part** — the part being ordered (selected from the Parts Catalog)\n- **Description** — auto-filled from the part, can be overridden\n- **Quantity** — how many units the customer wants\n- **Unit Price** — price per unit\n- **Line Total** — quantity x unit price (calculated automatically)\n- **Shipped Quantity** — how many have been shipped so far\n- **Remaining Quantity** — how many are still to ship\n\nThe line item table in the detail view color-codes shipped quantities: green when fully shipped, yellow when partially shipped.\n\n### How Sales Orders Connect to Other Features\n\n**Quotes:** A sales order can originate from an accepted quote. When a quote is converted to a sales order, the quote reference is preserved and visible in the SO detail. The Quote link in the detail panel is clickable.\n\n**Jobs (Kanban):** Sales order lines drive production. Each line can generate one or more jobs on the kanban board. Moving a job through production stages updates the SO's fulfillment status.\n\n**Shipments:** When goods are ready, you create shipments against SO lines. Each shipment line references an SO line and records how many units are being shipped. Partial shipments are supported — ship 50 of 100 now, the rest later.\n\n**Invoices:** Invoices are generated from shipments or directly from the SO. The invoice references the SO and its lines for billing accuracy.\n\n**Customers:** Every SO belongs to a customer. The customer link in the SO detail panel navigates directly to the customer record.\n\n### Financial Summary\n\nEach sales order displays:\n- **Subtotal** — sum of all line totals\n- **Tax** — subtotal multiplied by the tax rate percentage\n- **Total** — subtotal + tax\n\nThese values update automatically as line items are added or modified.\n\n### When to Use Sales Orders\n\n- When a customer confirms a quote and you need to formalize the commitment\n- When a customer sends a purchase order (PO) that you need to fulfill\n- When you need to track what has been shipped vs. what's still outstanding\n- When you need to generate invoices based on fulfilled orders\n- When you want full traceability from order through production to delivery","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Sales Orders — Guided Tour",
            Slug = "sales-orders-walkthrough",
            Summary = "A guided tour of the sales orders page: search, filters, data table columns, creating a new order with line items, and viewing order details.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 6,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/sales-orders"]""",
            Tags = """["sales-orders","sales","walkthrough"]""",
            ContentJson = """{"appRoute":"/sales-orders","startButtonLabel":"Tour Sales Orders","steps":[{"element":"[data-testid='new-so-btn']","popover":{"title":"New Sales Order","description":"Click here to create a new sales order. A split-layout dialog opens with line items on the left and order details (customer, credit terms, delivery date, tax rate, notes) on the right sidebar.","side":"bottom"}},{"element":".filters-bar app-input","popover":{"title":"Search Orders","description":"Search by order number, customer name, or customer PO. Press Enter to apply the search. Results update in the table below.","side":"bottom"}},{"element":".filters-bar app-select:first-of-type","popover":{"title":"Customer Filter","description":"Filter orders by customer. The dropdown lists all customers in the system. Select a customer to show only their orders.","side":"bottom"}},{"element":".filters-bar app-select:last-of-type","popover":{"title":"Status Filter","description":"Filter by order status: Draft, Confirmed, In Production, Partially Shipped, Shipped, Completed, or Cancelled. Each status has a color-coded chip in the table.","side":"bottom"}},{"element":"app-data-table","popover":{"title":"Sales Orders Table","description":"Lists all sales orders with columns: Order #, Customer, Cust PO, Status (color chip), Lines (count), Total (currency), Delivery date, and Created date. Click any row to open the detail dialog. Click column headers to sort.","side":"top"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Sales Orders Field Reference",
            Slug = "sales-orders-field-reference",
            Summary = "Complete reference for every field, button, status, validation rule, and table column in the Sales Orders module.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/sales-orders"]""",
            Tags = """["sales-orders","sales","reference"]""",
            ContentJson = """{"title":"Sales Orders Field Reference","groups":[{"heading":"Order Form Fields (Create/Edit Dialog — Right Sidebar)","items":[{"label":"Customer (required)","value":"Dropdown listing all customers. Determines billing context. Must select a customer before saving."},{"label":"Customer PO","value":"Text input, optional. The customer's purchase order number for their reference. Displayed in the table and detail view."},{"label":"Credit Terms","value":"Dropdown, optional. Payment terms such as Net 15, Net 30, Net 45, Net 60, Net 90, Due on Receipt, or 2/10 Net 30. Sourced from centralized CREDIT_TERMS_OPTIONS."},{"label":"Requested Delivery Date","value":"Date picker, optional. The date the customer wants the order delivered. Shown in the table column and detail view."},{"label":"Tax Rate (required)","value":"Number input with % suffix. The tax percentage applied to the subtotal. Defaults to 0. Must be >= 0. Updates the summary totals in real time."},{"label":"Notes","value":"Textarea, optional. Free-form notes about the order — special instructions, packaging requirements, etc. 3 rows visible."}]},{"heading":"Line Item Fields (Create/Edit Dialog — Left Panel)","items":[{"label":"Part (required)","value":"Autocomplete search field. Type to search active parts by part number or description. Shows 'Part # — Description' format. Only parts with Active status appear."},{"label":"Qty (required)","value":"Number input. Quantity ordered. Must be at least 1. Defaults to 1."},{"label":"Unit Price (required)","value":"Number input. Price per unit in dollars. Must be >= 0. Defaults to 0."},{"label":"Add button","value":"Adds the line to the table. Disabled when any line field is invalid. After adding, the line form resets for the next entry."},{"label":"Remove button (x icon)","value":"Red icon button on each line row. Removes the line item from the order. No confirmation dialog — immediate removal from the in-progress form."}]},{"heading":"Line Item Table Columns (Detail View)","items":[{"label":"Part #","value":"Part number in monospace font. Shows '—' if no part is linked."},{"label":"Description","value":"Line item description text."},{"label":"Qty","value":"Ordered quantity. Right-aligned."},{"label":"Shipped","value":"Quantity shipped so far. Right-aligned. Green text when fully shipped (shipped >= qty). Yellow text when partially shipped (shipped > 0 but < qty)."},{"label":"Remaining","value":"Quantity - Shipped. Right-aligned. Shows how many units are still to be fulfilled."},{"label":"Unit Price","value":"Price per unit, formatted as currency. Right-aligned."},{"label":"Total","value":"Line total (qty x unit price), formatted as currency. Right-aligned."}]},{"heading":"Order Statuses","items":[{"label":"Draft (gray chip)","value":"Order is being prepared. All fields editable. Can be deleted or cancelled. This is the initial status for new orders."},{"label":"Confirmed (blue/primary chip)","value":"Order has been confirmed and committed. Confirmed date is set automatically. Can still be cancelled but not deleted."},{"label":"In Production (info/teal chip)","value":"Linked jobs are active on the kanban board. Production work is underway."},{"label":"Partially Shipped (yellow/warning chip)","value":"Some line items have been shipped, but not all. Each line independently tracks its shipped vs. remaining quantity."},{"label":"Shipped (green/success chip)","value":"All line items are fully shipped. Fulfillment is complete."},{"label":"Completed (green/success chip)","value":"Order is fully closed — shipped and invoiced. No further action required."},{"label":"Cancelled (red/error chip)","value":"Order was cancelled. Only possible from Draft or Confirmed status. Once in production, cancellation is not allowed."}]},{"heading":"List Page Table Columns","items":[{"label":"Order #","value":"Sortable. Auto-generated order number displayed in bold monospace. Width: 120px."},{"label":"Customer","value":"Sortable. Customer name."},{"label":"Cust PO","value":"Sortable. Customer's purchase order number. Shows '—' when empty. Width: 100px."},{"label":"Status","value":"Sortable, filterable (enum). Color-coded chip: Draft (gray), Confirmed (blue), In Production (teal), Partially Shipped (yellow), Shipped (green), Completed (green), Cancelled (red). Width: 140px."},{"label":"Lines","value":"Sortable, center-aligned. Count of line items on the order. Width: 70px."},{"label":"Total","value":"Sortable, right-aligned. Order total formatted as currency. Width: 100px."},{"label":"Delivery","value":"Sortable, date type. Requested delivery date in MM/dd/yyyy format. Shows '—' when not set. Width: 110px."},{"label":"Created","value":"Sortable, date type. Date the order was created in MM/dd/yyyy format. Width: 110px."}]},{"heading":"List Page Filters","items":[{"label":"Search","value":"Text input. Filters by order number, customer name, or customer PO. Press Enter to apply."},{"label":"Customer","value":"Dropdown. Lists all customers plus an 'All Customers' option. Filters the table to show only orders for the selected customer."},{"label":"Status","value":"Dropdown. Lists all status values plus 'All Statuses'. Filters the table to show only orders with the selected status."}]},{"heading":"Detail View Sections","items":[{"label":"Header","value":"Shows receipt_long icon, order number, and customer name (clickable entity link to customer detail)."},{"label":"Status & Info Grid","value":"Status chip, Customer PO, linked Quote (clickable entity link), Credit Terms, Requested Delivery date, Confirmed date. Conditional — fields only shown when they have values."},{"label":"Barcode Info","value":"Scannable barcode for the order number. Compact mode."},{"label":"Totals Grid","value":"Subtotal, Tax (with rate %), and bold Total — all formatted as currency."},{"label":"Notes","value":"Free-form notes section. Only shown when notes are present."},{"label":"Line Items Table","value":"Full table with Part #, Description, Qty, Shipped, Remaining, Unit Price, Total. Shipped quantities are color-coded."},{"label":"Timestamps","value":"Created and Updated dates in MM/dd/yyyy format."},{"label":"Activity Log","value":"Chronological activity timeline for the order (EntityActivitySectionComponent)."}]},{"heading":"Buttons and Actions","items":[{"label":"New Sales Order (primary button)","value":"Opens the create dialog. data-testid: new-so-btn. Located in the page header."},{"label":"Create Order (dialog primary button)","value":"Saves the new order in Draft status. Disabled when form is invalid, no lines exist, or save is in progress. data-testid: so-save-btn. Shows validation popover on hover when disabled."},{"label":"Cancel (dialog)","value":"Closes the create dialog without saving."},{"label":"Confirm (detail, primary button)","value":"Moves Draft orders to Confirmed status. Records the confirmed date. Only visible when status is Draft."},{"label":"Cancel Order (detail)","value":"Cancels the order. Shows a confirmation dialog first. Only available for Draft and Confirmed orders."},{"label":"Delete (detail, danger button)","value":"Soft-deletes the order. Shows a confirmation dialog first. Only available for Draft orders."},{"label":"Close (detail, icon)","value":"Closes the detail dialog. X icon in the top-right corner."},{"label":"Row click (table)","value":"Opens the sales order detail dialog for the clicked row. URL updates to ?detail=sales-order:{id} for shareability."}]},{"heading":"Validation Rules","items":[{"label":"Customer","value":"Required. Must select a customer from the dropdown."},{"label":"Tax Rate","value":"Required. Must be a number >= 0."},{"label":"Line Items","value":"At least one line item must be added. Validation popover shows 'At least one line item is required' when empty."},{"label":"Line — Part","value":"Required. Must select a part from the autocomplete."},{"label":"Line — Quantity","value":"Required. Must be >= 1."},{"label":"Line — Unit Price","value":"Required. Must be >= 0."},{"label":"Submit popover","value":"When the form is invalid or lines are missing, hovering over the Create Order button shows a bulleted list of all violations."}]},{"heading":"Dialog Layout","items":[{"label":"Width","value":"1100px — split layout dialog."},{"label":"Left panel (main)","value":"Line items section: table of added lines + add-line form at the bottom (4-column layout: part autocomplete, qty, price, add button)."},{"label":"Right panel (sidebar)","value":"Order Details section (customer, PO, credit terms, delivery date, tax rate), Notes section (textarea), and Summary section (subtotal, tax, total — all computed in real time)."},{"label":"Footer","value":"Cancel and Create Order buttons. Equal width. Cancel left, primary right."},{"label":"Draft support","value":"Dialog auto-saves drafts to IndexedDB. Recoverable on page reload or login."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Sales Orders Knowledge Check",
            Slug = "sales-orders-quiz",
            Summary = "Test your knowledge of the Sales Orders module: statuses, line items, connections to quotes/shipments/invoices, and common workflows.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/sales-orders"]""",
            Tags = """["sales-orders","sales","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"so1","text":"A customer calls to confirm their quote and place an order. What is the correct first step in QB Engineer?","options":[{"id":"a","text":"Create a new job on the kanban board for the customer's parts"},{"id":"b","text":"Convert the accepted quote to a sales order, which preserves the quote reference and line items","isCorrect":true},{"id":"c","text":"Create an invoice directly from the quote"},{"id":"d","text":"Go to Shipments and create a shipment for the quoted parts"}],"explanation":"When a quote is accepted, you convert it to a sales order. This creates the SO with the quote's line items and preserves the quote reference link. From the SO, you then drive production, shipping, and invoicing."},{"id":"so2","text":"You're creating a new sales order. Which of the following is NOT required to save the order?","options":[{"id":"a","text":"Selecting a customer"},{"id":"b","text":"Adding at least one line item"},{"id":"c","text":"Setting the tax rate"},{"id":"d","text":"Entering the customer's PO number","isCorrect":true}],"explanation":"Customer PO is optional — not all customers send purchase orders. However, a customer selection, at least one line item, and a tax rate (which defaults to 0) are all required to save."},{"id":"so3","text":"A sales order is in Confirmed status. The customer wants to cancel. What can you do?","options":[{"id":"a","text":"Delete the order permanently from the system"},{"id":"b","text":"Cancel the order — cancellation is allowed from Draft or Confirmed status","isCorrect":true},{"id":"c","text":"Nothing — confirmed orders cannot be cancelled or modified"},{"id":"d","text":"Change the status back to Draft first, then cancel"}],"explanation":"Orders can be cancelled from either Draft or Confirmed status. Once an order moves to In Production or beyond, cancellation is no longer available. Note that Delete is only available for Draft orders."},{"id":"so4","text":"You've shipped 50 out of 100 units on a sales order line. What status does the order show?","options":[{"id":"a","text":"Shipped — any shipment changes the status"},{"id":"b","text":"In Production — the order stays in production until all units ship"},{"id":"c","text":"Partially Shipped — some lines have shipped quantities but not all are fully fulfilled","isCorrect":true},{"id":"d","text":"Draft — partial shipments don't affect status"}],"explanation":"When some but not all line items are fully shipped, the order shows Partially Shipped (yellow chip). Each line independently tracks its shipped quantity vs. ordered quantity. The order moves to Shipped only when all lines are fully fulfilled."},{"id":"so5","text":"In the sales order detail view, you notice a line item's shipped quantity is shown in green. What does this mean?","options":[{"id":"a","text":"The line item is on backorder"},{"id":"b","text":"The line item has been fully shipped — shipped quantity equals or exceeds ordered quantity","isCorrect":true},{"id":"c","text":"The line item's shipment is in transit"},{"id":"d","text":"The line item has been invoiced"}],"explanation":"Green text on the shipped quantity means the line is fully shipped (isFullyShipped = true). Yellow text means partially shipped (some shipped but not all). This color coding gives you a quick visual status of fulfillment per line."},{"id":"so6","text":"When adding a line item to a new sales order, where do parts come from?","options":[{"id":"a","text":"You type in a free-text part description — no part catalog lookup"},{"id":"b","text":"An autocomplete searches the Parts Catalog, showing only Active parts by part number and description","isCorrect":true},{"id":"c","text":"You select from a dropdown of all parts regardless of status"},{"id":"d","text":"Parts are automatically pulled from the linked quote"}],"explanation":"The line item part field is an autocomplete that searches only Active parts from the Parts Catalog. It shows results in 'Part # — Description' format. You must select a part from the search results."},{"id":"so7","text":"Where can you see how a sales order connects to its source quote?","options":[{"id":"a","text":"In the Sales Orders table — there's a Quote column showing the link"},{"id":"b","text":"In the detail view's info grid — the Quote field shows the quote number as a clickable entity link","isCorrect":true},{"id":"c","text":"Quotes and sales orders are not linked in the system"},{"id":"d","text":"Only in the Reports module under Order Traceability"}],"explanation":"The sales order detail view shows the linked quote number in the info grid. The quote number is a clickable entity link that opens the quote detail dialog, giving you full traceability from quote to order."},{"id":"so8","text":"You want to find all orders for a specific customer that haven't shipped yet. How do you filter the list?","options":[{"id":"a","text":"Use the Search field to type the customer name and manually scan for non-shipped statuses"},{"id":"b","text":"Set the Customer filter to the specific customer, then set the Status filter to Draft, Confirmed, or In Production","isCorrect":true},{"id":"c","text":"Go to the customer's detail page and check their Orders tab"},{"id":"d","text":"Both B and C would work","isCorrect":true}],"explanation":"The sales orders list page has both Customer and Status filters. Select the customer from the dropdown and then filter by status. You could also navigate to the customer's detail page and check their Orders tab for a customer-centric view."},{"id":"so9","text":"What happens to the financial summary when you change the tax rate on a sales order?","options":[{"id":"a","text":"Nothing changes until you save — totals are calculated server-side"},{"id":"b","text":"The Tax amount and Total update in real time as you type the new rate","isCorrect":true},{"id":"c","text":"You must click a Recalculate button to update the totals"},{"id":"d","text":"Tax is calculated per line item, not at the order level"}],"explanation":"The summary section in the create/edit dialog computes subtotal, tax amount (subtotal x rate%), and grand total in real time using computed signals. Changes to the tax rate or line items are reflected immediately."},{"id":"so10","text":"A Draft sales order can be deleted, but a Confirmed order cannot. Why?","options":[{"id":"a","text":"Confirmed orders have been communicated to the customer — deletion would break the audit trail. Cancellation preserves the record.","isCorrect":true},{"id":"b","text":"There is no difference — both can be deleted"},{"id":"c","text":"Confirmed orders are locked by the accounting system"},{"id":"d","text":"It's a bug — confirmed orders should also be deletable"}],"explanation":"Draft orders haven't been committed, so deletion is safe. Confirmed orders represent a business commitment — deleting them would break the audit trail. Instead, you cancel a confirmed order, which preserves the record with a Cancelled status for history and traceability."},{"id":"so11","text":"How does the create dialog for a sales order differ from a simple form dialog?","options":[{"id":"a","text":"It uses a standard single-column form layout like other create dialogs"},{"id":"b","text":"It uses a split layout — line items table and add-line form on the left, order details and summary on the right sidebar","isCorrect":true},{"id":"c","text":"It opens as a full-page view instead of a dialog"},{"id":"d","text":"It has a multi-step wizard with separate pages for details and lines"}],"explanation":"The SO create dialog uses a 1100px split layout. The left (main) panel contains the line items table and the add-line form with part autocomplete, quantity, and unit price. The right sidebar has order details (customer, PO, credit terms, delivery date, tax rate), notes, and a live summary showing subtotal, tax, and total."},{"id":"so12","text":"You click a sales order row in the table. What happens to the URL?","options":[{"id":"a","text":"Nothing — the detail opens as a popup with no URL change"},{"id":"b","text":"The URL updates to include ?detail=sales-order:{id}, making the view shareable and bookmarkable","isCorrect":true},{"id":"c","text":"The page navigates to /sales-orders/{id} as a separate route"},{"id":"d","text":"The URL changes to /sales-orders?selected={id}"}],"explanation":"Clicking a row opens the detail dialog via DetailDialogService, which updates the URL to include ?detail=sales-order:{id}. This means you can copy the URL and share it — anyone opening it will land on the same sales order detail. The URL is cleared when the dialog closes."}]}"""
        });

        Log.Information("Seeded Sales Orders training modules");
    }
}
